def feed_ranking(spec: dict) -> str:
    """Rank the user's feed (own posts plus followees' posts) by like count desc, then post id; comma-joined ids."""
    users = set(spec["users"])
    who = spec["who"]
    if who not in users:
        return ""
    authors = {who} | {f[1] for f in spec["follows"] if f[0] == who and f[1] in users}
    feed = [p["id"] for p in spec["posts"] if p["author"] in authors]
    counts = {pid: 0 for pid in feed}
    for l in spec["likes"]:
        if l[0] in users and l[1] in counts:
            counts[l[1]] += 1
    ranked = sorted(feed, key=lambda pid: (-counts[pid], pid))
    return ",".join(ranked)

